/**
 * Typed view over the committed competitor-benchmark results: basin vs other
 * optimization crates on matched (solver, problem) cases, recorded as
 * suboptimality-vs-time convergence traces.
 *
 * The JSON is generated by `web/scripts/collect-competitors.ts` (run via
 * `npm run collect:competitors`) from the `trace` harness output — never
 * hand-edited. This module just types it and adds display metadata, reusing
 * the solver/problem vocabulary from `./benchmarks`.
 */
import rawData from './competitor-benchmarks.json';
import { type Solver, SOLVER_LABELS, PROBLEM_LABELS } from './benchmarks';

export { type Solver, SOLVER_LABELS, PROBLEM_LABELS };

/** Competing libraries a case is run against. */
export type Library = 'basin' | 'argmin';

/** One `(time, suboptimality)` sample on a convergence trace. */
export interface TracePoint {
    /** Wall-clock time since iter 0, nanoseconds (median over reps). */
    tNs: number;
    /** Suboptimality `f(x) − f*`, floored at a small positive value. */
    subopt: number;
}

export interface CompetitorResult {
    solver: Solver;
    problem: string;
    n: number;
    library: Library;
    points: TracePoint[];
}

export interface CompetitorBenchmarks {
    /** ISO date (YYYY-MM-DD) the results were measured. */
    generatedAt: string;
    env: { os: string; arch: string; cpu: string };
    /** Iteration budget the harness capped each solve at. */
    iterations: number;
    results: CompetitorResult[];
}

export const COMPETITOR_BENCHMARKS = rawData as CompetitorBenchmarks;

export const LIBRARY_ORDER: Library[] = ['basin', 'argmin'];

export const LIBRARY_LABELS: Record<Library, string> = {
    basin: 'basin',
    argmin: 'argmin',
};

/** Line/legend colors per library, legible on light and dark backgrounds.
 * basin is indigo (its backend-chart `Vec<f64>` hue); argmin is amber. */
export const LIBRARY_COLORS: Record<Library, string> = {
    basin: '#6366f1',
    argmin: '#f59e0b',
};

/** One curated competitor case. */
export interface CompetitorCase {
    solver: Solver;
    problem: string;
    /** One line on what the case demonstrates. Shown under the card title. */
    blurb: string;
}

/**
 * The curated case set, in display order — all on Rosenbrock so the
 * comparison varies only the algorithm family. Keep in sync with `CASE_ORDER`
 * in `scripts/collect-competitors.ts` and the cases in
 * `crates/competitor-bench/src/bin/trace.rs`.
 */
export const COMPETITOR_CASES: CompetitorCase[] = [
    {
        solver: 'gd',
        problem: 'rosenbrock',
        blurb: 'Steepest descent with a More–Thuente line search — first-order, identical configuration on both sides.',
    },
    {
        solver: 'nm',
        problem: 'rosenbrock',
        blurb: 'Derivative-free Nelder–Mead from a bit-identical initial simplex (standard coefficients) — the implementations diverge in path and per-iteration cost.',
    },
    {
        solver: 'lbfgs',
        problem: 'rosenbrock',
        blurb: 'Limited-memory BFGS (m = 10, More–Thuente line search) — quasi-Newton; both converge well before the iteration cap.',
    },
];

/** Libraries a case actually has data for, in canonical order. */
export function librariesFor(solver: Solver, problem: string): Library[] {
    return LIBRARY_ORDER.filter((lib) =>
        COMPETITOR_BENCHMARKS.results.some(
            (r) => r.solver === solver && r.problem === problem && r.library === lib,
        ),
    );
}
